                    "type": "number",
                    "description": "Wind speed in mph.",
                },
                "feels_like": {
                    "type": "number",
                    "description": "Feels-like temperature in Celsius.",
                },
            },
            "required": ["location"],
        },
    },
    {
        "name": "generate_task_steps",
