      type: EventType.RUN_ERROR,
      runId,
      threadId,
      message: err.message,
      code: "AGENT_ERROR",
    });
  }

  res.end();
});

// ---------------------------------------------------------------------------
// Health check
// ---------------------------------------------------------------------------

app.get("/health", (_req: Request, res: Response) => {
  res.json({
    status: "ok",
    model: CLAUDE_MODEL,
    anthropic_api_key: process.env.ANTHROPIC_API_KEY ? "set" : "NOT SET",
  });
});

app.listen(PORT, HOST, () => {
  console.log(`[agent_server] Listening on http://${HOST}:${PORT}`);
});

