"use client";

import React, { useState } from "react";
import { CopilotKit, useLangGraphInterrupt } from "@copilotkit/react-core";
import {
  CopilotChat,
  useHumanInTheLoop,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";
import { z } from "zod";

interface Step {
  description: string;
  status: "disabled" | "enabled" | "executing";
}

export default function HitlDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="human_in_the_loop">
      <DemoContent />
    </CopilotKit>
  );
}

function DemoContent() {
  useConfigureSuggestions({
    suggestions: [
      {
        title: "Simple plan",
        message: "Please plan a trip to mars in 5 steps.",
      },
      {
        title: "Complex plan",
        message: "Please plan a pasta dish in 10 steps.",
      },
    ],
    available: "always",
  });

  useLangGraphInterrupt({
    render: ({ event, resolve }) => (
      <StepSelector
        steps={event.value?.steps || []}
        onConfirm={(selectedSteps) => {
          resolve(
            "The user selected the following steps: " +
              selectedSteps.map((s) => s.description).join(", "),
          );
        }}
      />
    ),
  });

  useHumanInTheLoop({
    agentId: "human_in_the_loop",
    name: "generate_task_steps",
    description: "Generates a list of steps for the user to perform",
    parameters: z.object({
      steps: z.array(
        z.object({
          description: z.string(),
          status: z.enum(["enabled", "disabled", "executing"]),
        }),
      ),
    }),
    render: ({ args, respond, status }: any) => (
      <StepsFeedback args={args} respond={respond} status={status} />
    ),
  });

  return (
    <div className="flex justify-center items-center h-full w-full">
      <div className="h-full w-full md:w-4/5 md:h-4/5 rounded-lg px-6">
        <CopilotChat
          agentId="human_in_the_loop"
          className="h-full rounded-2xl max-w-6xl mx-auto"
        />
      </div>
    </div>
  );
}

function StepSelector({
  steps,
  onConfirm,
}: {
  steps: Array<{ description?: string; status?: string } | string>;
  onConfirm: (steps: Step[]) => void;
}) {
  const [localSteps, setLocalSteps] = useState<Step[]>(() =>
    steps.map((s) => ({
      description: typeof s === "string" ? s : s.description || "",
      status: (typeof s === "object" && s.status === "disabled"
        ? "disabled"
        : "enabled") as Step["status"],
    })),
  );

  const enabledCount = localSteps.filter((s) => s.status === "enabled").length;

  return (
    <div
      data-testid="select-steps"
      style={{
        borderRadius: "16px",
        border: "1px solid #e5e5e0",
        background: "#fff",
        padding: "32px",
        boxShadow: "0 8px 30px rgba(0,0,0,0.08)",
        width: "520px",
      }}
    >
      <div className="mb-4 flex items-center justify-between">
        <h3 className="text-lg font-bold text-gray-800">Select Steps</h3>
        <span className="text-sm text-gray-500">
          {enabledCount}/{localSteps.length} selected
        </span>
      </div>
      <div className="space-y-1 mb-6">
        {localSteps.map((step, i) => (
          <label
            key={i}
            data-testid="step-item"
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              padding: "10px 16px",
              borderRadius: "8px",
              cursor: "pointer",
            }}
          >
            <input
              type="checkbox"
              checked={step.status === "enabled"}
              onChange={() =>
                setLocalSteps((prev) =>
                  prev.map((s, j) =>
                    j === i
                      ? {
                          ...s,
                          status:
                            s.status === "enabled" ? "disabled" : "enabled",
                        }
                      : s,
                  ),
                )
              }
              className="w-4 h-4 rounded"
            />
            <span
              className={
                step.status !== "enabled"
                  ? "line-through text-gray-400"
                  : "text-gray-800"
              }
              data-testid="step-text"
            >
              {step.description}
            </span>
          </label>
        ))}
      </div>
      <button
        onClick={() =>
          onConfirm(localSteps.filter((s) => s.status === "enabled"))
        }
        className="w-full rounded-lg bg-purple-600 px-4 py-2 text-white font-medium hover:bg-purple-700"
      >
        Perform Steps ({enabledCount})
      </button>
    </div>
  );
}

function StepsFeedback({
  args,
  respond,
  status,
}: {
  args: any;
  respond: any;
  status: any;
}) {
  const [localSteps, setLocalSteps] = useState<Step[]>([]);
  const [decided, setDecided] = useState<boolean | null>(null);

  React.useEffect(() => {
    if (
      status === "executing" &&
      localSteps.length === 0 &&
      args?.steps?.length > 0
    ) {
      setLocalSteps(args.steps);
    }
  }, [status, args?.steps, localSteps.length]);

  if (!args?.steps?.length) return null;

  const steps = localSteps.length > 0 ? localSteps : args.steps;
  const enabledCount = steps.filter((s: any) => s.status === "enabled").length;

  return (
    <div
      data-testid="select-steps"
      style={{
        borderRadius: "16px",
        border: "1px solid #e5e5e0",
        background: "#fff",
        padding: "32px",
        boxShadow: "0 8px 30px rgba(0,0,0,0.08)",
        width: "520px",
      }}
    >
      <div className="mb-4 flex items-center justify-between">
        <h3 className="text-lg font-bold text-gray-800">Review Steps</h3>
        <span className="text-sm text-gray-500">
          {enabledCount}/{steps.length} selected
        </span>
      </div>
      <div className="space-y-1 mb-6">
        {steps.map((step: any, i: number) => (
          <label
            key={i}
            data-testid="step-item"
            style={{
              display: "flex",
              alignItems: "center",
              gap: "12px",
              padding: "10px 16px",
              borderRadius: "8px",
              cursor: "pointer",
            }}
          >
            <input
              type="checkbox"
              checked={step.status === "enabled"}
              disabled={status !== "executing"}
              onChange={() =>
                setLocalSteps((prev) =>
                  prev.map((s, j) =>
                    j === i
                      ? {
                          ...s,
                          status:
                            s.status === "enabled" ? "disabled" : "enabled",
                        }
                      : s,
                  ),
                )
              }
              className="w-4 h-4 rounded"
            />
            <span
              className={
                step.status !== "enabled"
                  ? "line-through text-gray-400"
                  : "text-gray-800"
              }
              data-testid="step-text"
            >
              {step.description}
            </span>
          </label>
        ))}
      </div>
      {decided === null && (
        <div className="flex gap-3">
          <button
            disabled={status !== "executing"}
            onClick={() => {
              setDecided(false);
              respond?.({ accepted: false });
            }}
            className="flex-1 rounded-lg border border-gray-300 px-4 py-2 font-medium hover:bg-gray-50 disabled:opacity-50"
          >
            Reject
          </button>
          <button
            disabled={status !== "executing"}
            onClick={() => {
              setDecided(true);
              respond?.({
                accepted: true,
                steps: localSteps.filter((s) => s.status === "enabled"),
              });
            }}
            className="flex-1 rounded-lg bg-green-600 px-4 py-2 text-white font-medium hover:bg-green-700 disabled:opacity-50"
          >
            Confirm ({enabledCount})
          </button>
        </div>
      )}
      {decided !== null && (
        <div
          className={`text-center py-2 rounded-lg font-medium ${decided ? "bg-green-50 text-green-700" : "bg-red-50 text-red-700"}`}
        >
          {decided ? "Accepted" : "Rejected"}
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState } from "react";
import { CopilotKit } from "@copilotkit/react-core";
import {
  CopilotSidebar,
  useFrontendTool,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";
import { z } from "zod";

interface Proverb {
  text: string;
  gradient: string;
}

export default function GenUiToolBasedDemo() {
  return (
    <div
      style={{
        width: "100%",
        height: "100%",
        overflow: "hidden",
        position: "relative",
      }}
    >
      <CopilotKit runtimeUrl="/api/copilotkit" agent="gen-ui-tool-based">
        <SidebarWithSuggestions />
        <ProverbsDisplay />
      </CopilotKit>
    </div>
  );
}

function SidebarWithSuggestions() {
  useConfigureSuggestions({
    suggestions: [
      {
        title: "AI Proverb",
        message: "Create a proverb about artificial intelligence.",
      },
      {
        title: "Nature Proverb",
        message: "Create a proverb about nature and patience.",
      },
      {
        title: "Wisdom Proverb",
        message: "Generate a proverb about the value of wisdom.",
      },
    ],
    available: "always",
  });

  return (
    <CopilotSidebar
      defaultOpen={true}
      labels={{
        modalHeaderTitle: "Proverb Generator",
      }}
    />
  );
}

function ProverbsDisplay() {
  const [proverbs, setProverbs] = useState<Proverb[]>([
    {
      text: "CopilotKit may be new, but it's the best thing since sliced bread.",
      gradient: "linear-gradient(to bottom right, #f8fafc, #eff6ff)",
    },
  ]);

  useFrontendTool(
    {
      name: "generate_proverb",
      parameters: z.object({
        text: z.string().describe("The proverb text"),
        gradient: z.string().describe("CSS Gradient color for the background"),
      }),
      followUp: false,
      handler: async ({
        text,
        gradient,
      }: {
        text: string;
        gradient: string;
      }) => {
        const newProverb: Proverb = {
          text: text || "",
          gradient: gradient || "",
        };
        setProverbs((prev) => [
          newProverb,
          ...prev.filter(
            (p) =>
              p.text !==
              "CopilotKit may be new, but it's the best thing since sliced bread.",
          ),
        ]);
        return "Proverb generated!";
      },
      render: ({ args }: { args: Partial<Proverb> }) => {
        if (!args.text) return <></>;
        return <ProverbCard proverb={args as Proverb} />;
      },
    },
    [proverbs],
  );

  return (
    <div className="relative flex items-center justify-center h-full w-full">
      <div style={{ padding: "48px 80px", width: "100%", maxWidth: "56rem" }}>
        <div className="space-y-6">
          {proverbs.map((proverb, index) => (
            <ProverbCard key={index} proverb={proverb} />
          ))}
        </div>
      </div>
    </div>
  );
}

function ProverbCard({ proverb }: { proverb: Partial<Proverb> }) {
  return (
    <div
      data-testid="proverb-card"
      style={{
        position: "relative",
        borderRadius: "16px",
        margin: "24px 0",
        padding: "32px",
        maxWidth: "42rem",
        border: "1px solid #e2e8f0",
        overflow: "hidden",
        background:
          proverb.gradient ||
          "linear-gradient(to bottom right, #f8fafc, #eff6ff)",
      }}
    >
      <div className="absolute top-0 right-0 w-64 h-64 bg-gradient-to-br from-blue-400/10 to-purple-400/10 rounded-full blur-3xl -z-0" />
      <div className="absolute bottom-0 left-0 w-48 h-48 bg-gradient-to-tr from-indigo-400/10 to-pink-400/10 rounded-full blur-3xl -z-0" />

      <div className="relative z-10 flex flex-col items-center space-y-6">
        <div className="flex flex-col items-center text-center space-y-2">
          <p
            data-testid="proverb-text"
            className="font-serif font-bold text-2xl md:text-3xl bg-gradient-to-r from-slate-800 to-slate-600 bg-clip-text text-transparent tracking-wide leading-relaxed"
          >
            &ldquo;{proverb.text}&rdquo;
          </p>
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import {
  useFrontendTool,
  useRenderTool,
  useAgentContext,
  useConfigureSuggestions,
  CopilotChat,
} from "@copilotkit/react-core/v2";
import { CopilotKit } from "@copilotkit/react-core";
import { z } from "zod";
import { DemoErrorBoundary } from "../error-boundary";

export default function AgenticChatDemo() {
  useEffect(() => {
    console.log("[agentic-chat] Demo mounted");
  }, []);

  return (
    <DemoErrorBoundary demoName="Agentic Chat">
      <CopilotKit
        runtimeUrl="/api/copilotkit"
        agent="agentic_chat"
        onError={(error) => {
          console.error("[agentic-chat] CopilotKit error:", error);
        }}
      >
        <Chat />
      </CopilotKit>
    </DemoErrorBoundary>
  );
}

function Chat() {
  const [background, setBackground] = useState<string>("#fafaf9");

  useAgentContext({
    description: "Name of the user",
    value: "Bob",
  });

  useFrontendTool({
    name: "change_background",
    description:
