"use client";

import React, { useState, useEffect, useRef } from "react";
import { CopilotKit } from "@copilotkit/react-core";
import {
  CopilotSidebar,
  useAgent,
  UseAgentUpdate,
  useCopilotKit,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";

enum SkillLevel {
  BEGINNER = "Beginner",
  INTERMEDIATE = "Intermediate",
  ADVANCED = "Advanced",
}

enum CookingTime {
  FiveMin = "5 min",
  FifteenMin = "15 min",
  ThirtyMin = "30 min",
  FortyFiveMin = "45 min",
  SixtyPlusMin = "60+ min",
}

const cookingTimeValues = [
  { label: CookingTime.FiveMin, value: 0 },
  { label: CookingTime.FifteenMin, value: 1 },
  { label: CookingTime.ThirtyMin, value: 2 },
  { label: CookingTime.FortyFiveMin, value: 3 },
  { label: CookingTime.SixtyPlusMin, value: 4 },
];

enum SpecialPreferences {
  HighProtein = "High Protein",
  LowCarb = "Low Carb",
  Spicy = "Spicy",
  BudgetFriendly = "Budget-Friendly",
  OnePotMeal = "One-Pot Meal",
  Vegetarian = "Vegetarian",
  Vegan = "Vegan",
}

interface Ingredient {
  icon: string;
  name: string;
  amount: string;
}

interface RecipeData {
  title: string;
  skill_level: SkillLevel;
  cooking_time: CookingTime;
  special_preferences: string[];
  ingredients: Ingredient[];
  instructions: string[];
}

interface RecipeAgentState {
  recipe: RecipeData;
}

const INITIAL_STATE: RecipeAgentState = {
  recipe: {
    title: "Make Your Recipe",
    skill_level: SkillLevel.INTERMEDIATE,
    cooking_time: CookingTime.FortyFiveMin,
    special_preferences: [],
    ingredients: [
      { icon: "🥕", name: "Carrots", amount: "3 large, grated" },
      { icon: "🌾", name: "All-Purpose Flour", amount: "2 cups" },
    ],
    instructions: ["Preheat oven to 350\u00B0F (175\u00B0C)"],
  },
};

export default function SharedStateReadDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="shared-state-read">
      <div className="min-h-screen w-full flex items-center justify-center">
        <Recipe />
        <CopilotSidebar
          defaultOpen={true}
          labels={{
            modalHeaderTitle: "AI Recipe Assistant",
          }}
        />
      </div>
    </CopilotKit>
  );
}

function Recipe() {
  const { agent } = useAgent({
    agentId: "shared-state-read",
    updates: [UseAgentUpdate.OnStateChanged, UseAgentUpdate.OnRunStatusChanged],
  });
  const { copilotkit } = useCopilotKit();

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Create Italian recipe",
        message: "Create a delicious Italian pasta recipe.",
      },
      {
        title: "Make it healthier",
        message: "Make the recipe healthier with more vegetables.",
      },
      {
        title: "Suggest variations",
        message: "Suggest some creative variations of this recipe.",
      },
    ],
    available: "always",
  });

  const agentState = agent.state as RecipeAgentState | undefined;
  const setAgentState = (s: RecipeAgentState) => agent.setState(s);
  const isLoading = agent.isRunning;

  useEffect(() => {
    if (!agentState?.recipe) {
      setAgentState(INITIAL_STATE);
    }
  }, []);

  const [recipe, setRecipe] = useState(INITIAL_STATE.recipe);
  const [editingInstructionIndex, setEditingInstructionIndex] = useState<
    number | null
  >(null);
  const changedKeysRef = useRef<string[]>([]);

  const updateRecipe = (partialRecipe: Partial<RecipeData>) => {
    setAgentState({
      ...(agentState || INITIAL_STATE),
      recipe: {
        ...recipe,
        ...partialRecipe,
      },
    });
    setRecipe({
      ...recipe,
      ...partialRecipe,
    });
  };

  // Sync agent state changes into local recipe state
  const newRecipeState = { ...recipe };
  const newChangedKeys: string[] = [];

  for (const key in recipe) {
    if (
      agentState?.recipe &&
      (agentState.recipe as any)[key] !== undefined &&
      (agentState.recipe as any)[key] !== null
    ) {
      let agentValue = (agentState.recipe as any)[key];
      const recipeValue = (recipe as any)[key];

      if (typeof agentValue === "string") {
        agentValue = agentValue.replace(/\\n/g, "\n");
      }

      if (JSON.stringify(agentValue) !== JSON.stringify(recipeValue)) {
        (newRecipeState as any)[key] = agentValue;
        newChangedKeys.push(key);
      }
    }
  }

  if (newChangedKeys.length > 0) {
    changedKeysRef.current = newChangedKeys;
  } else if (!isLoading) {
    changedKeysRef.current = [];
  }

  useEffect(() => {
    setRecipe(newRecipeState);
  }, [JSON.stringify(newRecipeState)]);

  const handleTitleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    updateRecipe({ title: event.target.value });
  };

  const handleSkillLevelChange = (
    event: React.ChangeEvent<HTMLSelectElement>,
  ) => {
    updateRecipe({ skill_level: event.target.value as SkillLevel });
  };

  const handleDietaryChange = (preference: string, checked: boolean) => {
    if (checked) {
      updateRecipe({
        special_preferences: [...recipe.special_preferences, preference],
      });
    } else {
      updateRecipe({
        special_preferences: recipe.special_preferences.filter(
          (p) => p !== preference,
        ),
      });
    }
  };

  const handleCookingTimeChange = (
    event: React.ChangeEvent<HTMLSelectElement>,
  ) => {
    updateRecipe({
      cooking_time: cookingTimeValues[Number(event.target.value)].label,
    });
  };

  const addIngredient = () => {
    updateRecipe({
      ingredients: [
        ...recipe.ingredients,
        { icon: "🍴", name: "", amount: "" },
      ],
    });
  };

  const updateIngredient = (
    index: number,
    field: keyof Ingredient,
    value: string,
  ) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients[index] = {
      ...updatedIngredients[index],
      [field]: value,
    };
    updateRecipe({ ingredients: updatedIngredients });
  };

  const removeIngredient = (index: number) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients.splice(index, 1);
    updateRecipe({ ingredients: updatedIngredients });
  };

  const addInstruction = () => {
    const newIndex = recipe.instructions.length;
    updateRecipe({ instructions: [...recipe.instructions, ""] });
    setEditingInstructionIndex(newIndex);
  };

  const updateInstruction = (index: number, value: string) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions[index] = value;
    updateRecipe({ instructions: updatedInstructions });
  };

  const removeInstruction = (index: number) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions.splice(index, 1);
    updateRecipe({ instructions: updatedInstructions });
  };

  return (
    <form
      data-testid="recipe-card"
      className="max-w-2xl mx-auto p-6 bg-white rounded-2xl shadow-lg border border-gray-100"
    >
      {/* Recipe Title */}
      <div className="mb-6">
        <input
          type="text"
          value={recipe.title || ""}
          onChange={handleTitleChange}
          className="text-3xl font-bold w-full border-none outline-none bg-transparent"
        />

        <div className="flex gap-4 mt-3">
          <div className="flex items-center gap-1">
            <span>🕒</span>
            <select
              className="text-sm border rounded px-2 py-1"
              value={
                cookingTimeValues.find((t) => t.label === recipe.cooking_time)
                  ?.value || 3
              }
              onChange={handleCookingTimeChange}
            >
              {cookingTimeValues.map((time) => (
                <option key={time.value} value={time.value}>
                  {time.label}
                </option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-1">
            <span>🏆</span>
            <select
              className="text-sm border rounded px-2 py-1"
              value={recipe.skill_level}
              onChange={handleSkillLevelChange}
            >
              {Object.values(SkillLevel).map((level) => (
                <option key={level} value={level}>
                  {level}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Dietary Preferences */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("special_preferences") && <Ping />}
        <h2 className="text-lg font-semibold mb-2">Dietary Preferences</h2>
        <div className="flex flex-wrap gap-2">
          {Object.values(SpecialPreferences).map((option) => (
            <label
              key={option}
              className="flex items-center gap-1 text-sm bg-gray-50 px-3 py-1.5 rounded-full cursor-pointer hover:bg-gray-100"
            >
              <input
                type="checkbox"
                checked={recipe.special_preferences.includes(option)}
                onChange={(e) => handleDietaryChange(option, e.target.checked)}
              />
              <span>{option}</span>
            </label>
          ))}
        </div>
      </div>

      {/* Ingredients */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("ingredients") && <Ping />}
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-semibold">Ingredients</h2>
          <button
            data-testid="add-ingredient-button"
            type="button"
            className="text-sm text-blue-600 hover:text-blue-800"
            onClick={addIngredient}
          >
            + Add Ingredient
          </button>
        </div>
        <div data-testid="ingredients-container" className="space-y-2">
          {recipe.ingredients.map((ingredient, index) => (
            <div
              key={index}
              data-testid="ingredient-card"
              className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg"
            >
              <div className="text-2xl">{ingredient.icon || "🍴"}</div>
              <div className="flex-1 flex gap-2">
                <input
                  type="text"
                  value={ingredient.name || ""}
                  onChange={(e) =>
                    updateIngredient(index, "name", e.target.value)
                  }
                  placeholder="Ingredient name"
                  className="flex-1 text-sm border rounded px-2 py-1"
                />
                <input
                  type="text"
                  value={ingredient.amount || ""}
                  onChange={(e) =>
                    updateIngredient(index, "amount", e.target.value)
                  }
                  placeholder="Amount"
                  className="w-32 text-sm border rounded px-2 py-1"
                />
              </div>
              <button
                type="button"
                className="text-gray-400 hover:text-red-500 text-xl"
                onClick={() => removeIngredient(index)}
              >
                x
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Instructions */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("instructions") && <Ping />}
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-semibold">Instructions</h2>
          <button
            type="button"
            className="text-sm text-blue-600 hover:text-blue-800"
            onClick={addInstruction}
          >
            + Add Step
          </button>
        </div>
        <div data-testid="instructions-container" className="space-y-3">
          {recipe.instructions.map((instruction, index) => (
            <div key={index} className="flex items-start gap-3">
              <div className="flex-shrink-0 w-7 h-7 rounded-full bg-blue-500 text-white flex items-center justify-center text-sm font-bold">
                {index + 1}
              </div>
              <div
                className="flex-1 relative"
                onClick={() => setEditingInstructionIndex(index)}
              >
                <textarea
                  className="w-full text-sm border rounded px-3 py-2 resize-none"
                  value={instruction || ""}
                  onChange={(e) => updateInstruction(index, e.target.value)}
                  placeholder="Enter cooking instruction..."
                  onFocus={() => setEditingInstructionIndex(index)}
                  onBlur={() => setEditingInstructionIndex(null)}
                  rows={2}
                />
              </div>
              <button
                type="button"
                className="text-gray-400 hover:text-red-500 text-xl mt-1"
                onClick={() => removeInstruction(index)}
              >
                x
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Improve with AI Button */}
      <div className="flex justify-center">
        <button
          data-testid="improve-button"
          className={`px-6 py-3 rounded-xl font-semibold text-white transition-all ${
            isLoading
              ? "bg-gray-400 cursor-not-allowed"
              : "bg-gradient-to-r from-blue-500 to-purple-500 hover:from-blue-600 hover:to-purple-600 shadow-lg"
          }`}
          type="button"
          onClick={() => {
            if (!isLoading) {
              agent.addMessage({
                id: crypto.randomUUID(),
                role: "user",
                content: "Improve the recipe",
              });
              copilotkit.runAgent({ agent });
            }
          }}
          disabled={isLoading}
        >
          {isLoading ? "Please Wait..." : "Improve with AI"}
        </button>
      </div>
    </form>
  );
}

function Ping() {
  return (
    <span className="absolute -top-1 -right-1 flex h-3 w-3">
      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75" />
      <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500" />
    </span>
  );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { CopilotKit } from "@copilotkit/react-core";
import {
  CopilotSidebar,
  useAgent,
  UseAgentUpdate,
  useCopilotKit,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";

enum SkillLevel {
  BEGINNER = "Beginner",
  INTERMEDIATE = "Intermediate",
  ADVANCED = "Advanced",
}

enum CookingTime {
  FiveMin = "5 min",
  FifteenMin = "15 min",
  ThirtyMin = "30 min",
  FortyFiveMin = "45 min",
  SixtyPlusMin = "60+ min",
}

const cookingTimeValues = [
  { label: CookingTime.FiveMin, value: 0 },
  { label: CookingTime.FifteenMin, value: 1 },
  { label: CookingTime.ThirtyMin, value: 2 },
  { label: CookingTime.FortyFiveMin, value: 3 },
  { label: CookingTime.SixtyPlusMin, value: 4 },
];

enum SpecialPreferences {
  HighProtein = "High Protein",
  LowCarb = "Low Carb",
  Spicy = "Spicy",
  BudgetFriendly = "Budget-Friendly",
  OnePotMeal = "One-Pot Meal",
  Vegetarian = "Vegetarian",
  Vegan = "Vegan",
}

interface Ingredient {
  icon: string;
  name: string;
  amount: string;
}

interface RecipeData {
  title: string;
  skill_level: SkillLevel;
  cooking_time: CookingTime;
  special_preferences: string[];
  ingredients: Ingredient[];
  instructions: string[];
}

interface RecipeAgentState {
  recipe: RecipeData;
}

const INITIAL_STATE: RecipeAgentState = {
  recipe: {
    title: "Make Your Recipe",
    skill_level: SkillLevel.INTERMEDIATE,
    cooking_time: CookingTime.FortyFiveMin,
    special_preferences: [],
    ingredients: [
      { icon: "🥕", name: "Carrots", amount: "3 large, grated" },
      { icon: "🌾", name: "All-Purpose Flour", amount: "2 cups" },
    ],
    instructions: ["Preheat oven to 350\u00B0F (175\u00B0C)"],
  },
};

export default function SharedStateWriteDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="shared-state-write">
      <div className="min-h-screen w-full flex items-center justify-center">
        <RecipeEditor />
        <CopilotSidebar
          defaultOpen={true}
          labels={{
            modalHeaderTitle: "AI Recipe Assistant",
          }}
        />
      </div>
    </CopilotKit>
  );
}

function RecipeEditor() {
  const { agent } = useAgent({
    agentId: "shared-state-write",
    updates: [UseAgentUpdate.OnStateChanged, UseAgentUpdate.OnRunStatusChanged],
  });
  const { copilotkit } = useCopilotKit();

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Create Italian recipe",
        message: "Create a delicious Italian pasta recipe.",
      },
      {
        title: "Add more spice",
        message: "Make the recipe spicier with chili and pepper.",
      },
      {
        title: "Make it vegan",
        message: "Convert this recipe to be fully vegan.",
      },
    ],
    available: "always",
  });

  const agentState = agent.state as RecipeAgentState | undefined;
  const setAgentState = (s: RecipeAgentState) => agent.setState(s);
  const isLoading = agent.isRunning;

  useEffect(() => {
    if (!agentState?.recipe) {
      setAgentState(INITIAL_STATE);
    }
  }, []);

  const [recipe, setRecipe] = useState(INITIAL_STATE.recipe);
  const [editingInstructionIndex, setEditingInstructionIndex] = useState<
    number | null
  >(null);
  const changedKeysRef = useRef<string[]>([]);

  const updateRecipe = (partialRecipe: Partial<RecipeData>) => {
    const updated = { ...recipe, ...partialRecipe };
    setAgentState({
      ...(agentState || INITIAL_STATE),
      recipe: updated,
    });
    setRecipe(updated);
  };

  // Sync agent state into local state
  const newRecipeState = { ...recipe };
  const newChangedKeys: string[] = [];

  for (const key in recipe) {
    if (
      agentState?.recipe &&
      (agentState.recipe as any)[key] !== undefined &&
      (agentState.recipe as any)[key] !== null
    ) {
      let agentValue = (agentState.recipe as any)[key];
      const recipeValue = (recipe as any)[key];

      if (typeof agentValue === "string") {
        agentValue = agentValue.replace(/\\n/g, "\n");
      }

      if (JSON.stringify(agentValue) !== JSON.stringify(recipeValue)) {
        (newRecipeState as any)[key] = agentValue;
        newChangedKeys.push(key);
      }
    }
  }

  if (newChangedKeys.length > 0) {
    changedKeysRef.current = newChangedKeys;
  } else if (!isLoading) {
    changedKeysRef.current = [];
  }

  useEffect(() => {
    setRecipe(newRecipeState);
  }, [JSON.stringify(newRecipeState)]);

  const handleTitleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    updateRecipe({ title: event.target.value });
  };

  const handleSkillLevelChange = (
    event: React.ChangeEvent<HTMLSelectElement>,
  ) => {
    updateRecipe({ skill_level: event.target.value as SkillLevel });
  };

  const handleDietaryChange = (preference: string, checked: boolean) => {
    if (checked) {
      updateRecipe({
        special_preferences: [...recipe.special_preferences, preference],
      });
    } else {
      updateRecipe({
        special_preferences: recipe.special_preferences.filter(
          (p) => p !== preference,
        ),
      });
    }
  };

  const handleCookingTimeChange = (
    event: React.ChangeEvent<HTMLSelectElement>,
  ) => {
    updateRecipe({
      cooking_time: cookingTimeValues[Number(event.target.value)].label,
    });
  };

  const addIngredient = () => {
    updateRecipe({
      ingredients: [
        ...recipe.ingredients,
        { icon: "🍴", name: "", amount: "" },
      ],
    });
  };

  const updateIngredient = (
    index: number,
    field: keyof Ingredient,
    value: string,
  ) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients[index] = {
      ...updatedIngredients[index],
      [field]: value,
    };
    updateRecipe({ ingredients: updatedIngredients });
  };

  const removeIngredient = (index: number) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients.splice(index, 1);
    updateRecipe({ ingredients: updatedIngredients });
  };

  const addInstruction = () => {
    const newIndex = recipe.instructions.length;
    updateRecipe({ instructions: [...recipe.instructions, ""] });
    setEditingInstructionIndex(newIndex);
  };

  const updateInstruction = (index: number, value: string) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions[index] = value;
    updateRecipe({ instructions: updatedInstructions });
  };

  const removeInstruction = (index: number) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions.splice(index, 1);
    updateRecipe({ instructions: updatedInstructions });
  };

  return (
    <form
      data-testid="recipe-card"
      className="max-w-2xl mx-auto p-6 bg-white rounded-2xl shadow-lg border border-gray-100"
    >
      {/* Recipe Title */}
      <div className="mb-6">
        <input
          type="text"
          value={recipe.title || ""}
          onChange={handleTitleChange}
          className="text-3xl font-bold w-full border-none outline-none bg-transparent"
          placeholder="Recipe title..."
        />

        <div className="flex gap-4 mt-3">
          <div className="flex items-center gap-1">
            <span>🕒</span>
            <select
              className="text-sm border rounded px-2 py-1"
              value={
                cookingTimeValues.find((t) => t.label === recipe.cooking_time)
                  ?.value || 3
              }
              onChange={handleCookingTimeChange}
            >
              {cookingTimeValues.map((time) => (
                <option key={time.value} value={time.value}>
                  {time.label}
                </option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-1">
            <span>🏆</span>
            <select
              className="text-sm border rounded px-2 py-1"
              value={recipe.skill_level}
              onChange={handleSkillLevelChange}
            >
              {Object.values(SkillLevel).map((level) => (
                <option key={level} value={level}>
                  {level}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Dietary Preferences */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("special_preferences") && <Ping />}
        <h2 className="text-lg font-semibold mb-2">Dietary Preferences</h2>
        <div className="flex flex-wrap gap-2">
          {Object.values(SpecialPreferences).map((option) => (
            <label
              key={option}
              className="flex items-center gap-1 text-sm bg-gray-50 px-3 py-1.5 rounded-full cursor-pointer hover:bg-gray-100"
            >
              <input
                type="checkbox"
                checked={recipe.special_preferences.includes(option)}
                onChange={(e) => handleDietaryChange(option, e.target.checked)}
              />
              <span>{option}</span>
            </label>
          ))}
        </div>
      </div>

      {/* Ingredients */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("ingredients") && <Ping />}
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-semibold">Ingredients</h2>
          <button
            data-testid="add-ingredient-button"
            type="button"
            className="text-sm text-blue-600 hover:text-blue-800"
            onClick={addIngredient}
          >
            + Add Ingredient
          </button>
        </div>
        <div data-testid="ingredients-container" className="space-y-2">
          {recipe.ingredients.map((ingredient, index) => (
            <div
              key={index}
              data-testid="ingredient-card"
              className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg"
            >
              <div className="text-2xl">{ingredient.icon || "🍴"}</div>
              <div className="flex-1 flex gap-2">
                <input
                  type="text"
                  value={ingredient.name || ""}
                  onChange={(e) =>
                    updateIngredient(index, "name", e.target.value)
                  }
                  placeholder="Ingredient name"
                  className="flex-1 text-sm border rounded px-2 py-1"
                />
                <input
                  type="text"
                  value={ingredient.amount || ""}
                  onChange={(e) =>
                    updateIngredient(index, "amount", e.target.value)
                  }
                  placeholder="Amount"
                  className="w-32 text-sm border rounded px-2 py-1"
                />
              </div>
              <button
                type="button"
                className="text-gray-400 hover:text-red-500 text-xl"
                onClick={() => removeIngredient(index)}
              >
                x
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Instructions */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("instructions") && <Ping />}
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-semibold">Instructions</h2>
          <button
            type="button"
            className="text-sm text-blue-600 hover:text-blue-800"
            onClick={addInstruction}
          >
            + Add Step
          </button>
        </div>
        <div data-testid="instructions-container" className="space-y-3">
          {recipe.instructions.map((instruction, index) => (
            <div key={index} className="flex items-start gap-3">
              <div className="flex-shrink-0 w-7 h-7 rounded-full bg-blue-500 text-white flex items-center justify-center text-sm font-bold">
                {index + 1}
              </div>
              <div
                className="flex-1 relative"
                onClick={() => setEditingInstructionIndex(index)}
              >
                <textarea
                  className="w-full text-sm border rounded px-3 py-2 resize-none"
                  value={instruction || ""}
                  onChange={(e) => updateInstruction(index, e.target.value)}
                  placeholder="Enter cooking instruction..."
                  onFocus={() => setEditingInstructionIndex(index)}
                  onBlur={() => setEditingInstructionIndex(null)}
                  rows={2}
                />
              </div>
              <button
                type="button"
                className="text-gray-400 hover:text-red-500 text-xl mt-1"
                onClick={() => removeInstruction(index)}
              >
                x
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Improve with AI Button */}
      <div className="flex justify-center">
        <button
          data-testid="improve-button"
          className={`px-6 py-3 rounded-xl font-semibold text-white transition-all ${
            isLoading
              ? "bg-gray-400 cursor-not-allowed"
              : "bg-gradient-to-r from-blue-500 to-purple-500 hover:from-blue-600 hover:to-purple-600 shadow-lg"
          }`}
          type="button"
          onClick={() => {
            if (!isLoading) {
              agent.addMessage({
                id: crypto.randomUUID(),
                role: "user",
                content: "Improve the recipe",
              });
              copilotkit.runAgent({ agent });
            }
          }}
          disabled={isLoading}
        >
          {isLoading ? "Please Wait..." : "Improve with AI"}
        </button>
      </div>
    </form>
  );
}

function Ping() {
  return (
    <span className="absolute -top-1 -right-1 flex h-3 w-3">
      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75" />
      <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500" />
    </span>
  );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { CopilotKit } from "@copilotkit/react-core";
import {
  CopilotSidebar,
  useAgent,
  UseAgentUpdate,
  useHumanInTheLoop,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";
import { z } from "zod";

interface AgentState {
  document: string;
}

export default function SharedStateStreamingDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="shared-state-streaming">
      <div className="min-h-screen w-full">
        <CopilotSidebar
          defaultOpen={true}
          labels={{
            modalHeaderTitle: "AI Document Editor",
          }}
        />
        <DocumentEditor />
      </div>
    </CopilotKit>
  );
}

function DocumentEditor() {
  const [document, setDocument] = useState("");
  const [placeholderVisible, setPlaceholderVisible] = useState(true);
  const [currentDocument, setCurrentDocument] = useState("");
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Write a pirate story",
        message: "Please write a story about a pirate named Candy Beard.",
      },
      {
        title: "Write a mermaid story",
        message: "Please write a story about a mermaid named Luna.",
      },
      {
        title: "Add character",
        message: "Please add a character named Courage.",
      },
    ],
    available: "always",
  });

  const { agent } = useAgent({
    agentId: "shared-state-streaming",
    updates: [UseAgentUpdate.OnStateChanged, UseAgentUpdate.OnRunStatusChanged],
  });

  const agentState = agent.state as AgentState | undefined;
  const setAgentState = (s: AgentState) => agent.setState(s);
  const isLoading = agent.isRunning;

  const wasRunning = useRef(false);

  useEffect(() => {
    if (isLoading) {
      setCurrentDocument(document);
    }
  }, [isLoading]);

  // When run finishes, apply final state
  useEffect(() => {
    if (wasRunning.current && !isLoading) {
      if (agentState?.document) {
        setDocument(agentState.document);
        setCurrentDocument(agentState.document);
      }
    }
    wasRunning.current = isLoading;
  }, [isLoading]);

  // Stream updates while loading
  useEffect(() => {
    if (isLoading && agentState?.document) {
      setDocument(agentState.document);
    }
  }, [agentState?.document]);

  // Sync local edits to agent state
  useEffect(() => {
    setPlaceholderVisible(document.length === 0);
    if (!isLoading) {
      setCurrentDocument(document);
      setAgentState({ document });
    }
  }, [document]);

  // Human-in-the-loop for confirming changes
  useHumanInTheLoop(
    {
      agentId: "shared-state-streaming",
      name: "write_document",
      description: "Present the proposed changes to the user for review",
      parameters: z.object({
        document: z
          .string()
          .describe("The full updated document in markdown format"),
      }),
      render({
        args,
        status,
        respond,
      }: {
        args: { document?: string };
        status: string;
        respond?: (result: unknown) => Promise<void>;
      }) {
        if (status === "executing") {
          return (
            <ConfirmChanges
              args={args}
              respond={respond}
              status={status}
              onReject={() => {
                setDocument(currentDocument);
                setAgentState({
                  document: currentDocument,
                });
              }}
              onConfirm={() => {
                const newDoc = agentState?.document || "";
                setDocument(newDoc);
                setCurrentDocument(newDoc);
                setAgentState({
                  document: newDoc,
                });
              }}
            />
          );
        }
        return <></>;
      },
    },
    [agentState?.document],
  );

  return (
    <div className="relative min-h-screen w-full p-6">
      {placeholderVisible && (
        <div className="absolute top-10 left-10 pointer-events-none text-gray-400">
          Write whatever you want here...
        </div>
      )}
      <textarea
        ref={textareaRef}
        className="w-full min-h-screen p-4 text-base leading-relaxed border-none outline-none resize-none bg-transparent"
        value={document}
        onChange={(e) => setDocument(e.target.value)}
        readOnly={isLoading}
        placeholder=""
      />
    </div>
  );
}

interface ConfirmChangesProps {
  args: { document?: string };
  respond: ((result: unknown) => Promise<void>) | undefined;
  status: string;
  onReject: () => void;
  onConfirm: () => void;
}

function ConfirmChanges({
  args,
  respond,
  status,
  onReject,
  onConfirm,
}: ConfirmChangesProps) {
  const [accepted, setAccepted] = useState<boolean | null>(null);

  return (
    <div
      data-testid="confirm-changes-modal"
      className="bg-white p-6 rounded shadow-lg border border-gray-200 mt-5 mb-5"
    >
      <h2 className="text-lg font-bold mb-4">Confirm Changes</h2>
      <p className="mb-6">Do you want to accept the changes?</p>
      {accepted === null && (
        <div className="flex justify-end space-x-4">
          <button
            data-testid="reject-button"
            className={`bg-gray-200 text-black py-2 px-4 rounded disabled:opacity-50 ${
              status === "executing" ? "cursor-pointer" : "cursor-default"
            }`}
            disabled={status !== "executing"}
            onClick={() => {
              if (respond) {
                setAccepted(false);
                onReject();
                respond({ accepted: false });
              }
            }}
          >
            Reject
          </button>
          <button
            data-testid="confirm-button"
            className={`bg-black text-white py-2 px-4 rounded disabled:opacity-50 ${
              status === "executing" ? "cursor-pointer" : "cursor-default"
            }`}
            disabled={status !== "executing"}
            onClick={() => {
              if (respond) {
                setAccepted(true);
                onConfirm();
                respond({ accepted: true });
              }
            }}
          >
            Confirm
          </button>
        </div>
      )}
      {accepted !== null && (
        <div className="flex justify-end">
          <div
            data-testid="status-display"
            className="mt-4 bg-gray-200 text-black py-2 px-4 rounded inline-block"
          >
            {accepted ? "Accepted" : "Rejected"}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useEffect } from "react";
import { CopilotKit, useLangGraphInterrupt } from "@copilotkit/react-core";
import {
  CopilotSidebar,
  useAgent,
  UseAgentUpdate,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";

// Travel planning data types
interface Flight {
  airline: string;
  arrival: string;
  departure: string;
  duration: string;
  price: string;
}

interface Hotel {
  location: string;
  name: string;
  price_per_night: string;
  rating: string;
}

interface Experience {
  name: string;
  description: string;
  location: string;
  type: string;
}

interface Itinerary {
  hotel?: Hotel;
  flight?: Flight;
  experiences?: Experience[];
}

type AvailableAgents = "flights" | "hotels" | "experiences" | "supervisor";

interface TravelAgentState {
  experiences: Experience[];
  flights: Flight[];
  hotels: Hotel[];
  itinerary: Itinerary;
  planning_step: string;
  active_agent: AvailableAgents;
}

const INITIAL_STATE: TravelAgentState = {
  itinerary: {},
  experiences: [],
  flights: [],
  hotels: [],
  planning_step: "start",
  active_agent: "supervisor",
};

interface InterruptEvent<TAgent extends AvailableAgents> {
  message: string;
  options: TAgent extends "flights"
    ? Flight[]
    : TAgent extends "hotels"
      ? Hotel[]
      : never;
  recommendation: TAgent extends "flights"
    ? Flight
    : TAgent extends "hotels"
      ? Hotel
      : never;
  agent: TAgent;
}

export default function SubagentsDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="subagents">
      <div className="min-h-screen w-full flex">
        <TravelPlanner />
        <CopilotSidebar
          agentId="subagents"
          defaultOpen={true}
          labels={{
            modalHeaderTitle: "Travel Planning Assistant",
          }}
        />
      </div>
    </CopilotKit>
  );
}

function InterruptHumanInTheLoop<TAgent extends AvailableAgents>({
  event,
  resolve,
}: {
  event: { value: InterruptEvent<TAgent> };
  resolve: (value: string) => void;
}) {
  const { message, options, agent, recommendation } = event.value;

  const formatAgentName = (agentName: string) => {
    switch (agentName) {
      case "flights":
        return "Flights Agent";
      case "hotels":
        return "Hotels Agent";
      case "experiences":
        return "Experiences Agent";
      default:
        return `${agentName} Agent`;
    }
  };

  const handleOptionSelect = (option: Flight | Hotel) => {
    resolve(JSON.stringify(option));
  };

  return (
    <div className="p-4 bg-blue-50 rounded-lg border border-blue-200 my-3">
      <p className="font-medium mb-3">
        {formatAgentName(agent)}: {message}
      </p>

      <div className="space-y-2">
        {options.map((opt, idx) => {
          if ("airline" in opt) {
            const isRecommended =
              (recommendation as Flight).airline === opt.airline;
            return (
              <button
                key={idx}
                className={`w-full text-left p-3 rounded-lg border transition-colors ${
                  isRecommended
                    ? "border-yellow-400 bg-yellow-50 hover:bg-yellow-100"
                    : "border-gray-200 bg-white hover:bg-gray-50"
                }`}
                onClick={() => handleOptionSelect(opt)}
              >
                {isRecommended && (
                  <span className="text-xs font-semibold text-yellow-600 mb-1 block">
                    Recommended
                  </span>
                )}
                <div className="flex justify-between items-center">
                  <span className="font-medium">{opt.airline}</span>
                  <span className="text-green-600 font-semibold">
                    {opt.price}
                  </span>
                </div>
                <div className="text-sm text-gray-600 mt-1">
                  {opt.departure} &rarr; {opt.arrival}
                </div>
                <div className="text-xs text-gray-500">{opt.duration}</div>
              </button>
            );
          }

          const isRecommended = (recommendation as Hotel).name === opt.name;
          return (
            <button
              key={idx}
              className={`w-full text-left p-3 rounded-lg border transition-colors ${
                isRecommended
                  ? "border-yellow-400 bg-yellow-50 hover:bg-yellow-100"
                  : "border-gray-200 bg-white hover:bg-gray-50"
              }`}
              onClick={() => handleOptionSelect(opt)}
            >
              {isRecommended && (
                <span className="text-xs font-semibold text-yellow-600 mb-1 block">
                  Recommended
                </span>
              )}
              <div className="flex justify-between items-center">
                <span className="font-medium">{opt.name}</span>
                <span className="text-sm">{opt.rating}</span>
              </div>
              <div className="text-sm text-gray-600 mt-1">{opt.location}</div>
              <div className="text-xs text-gray-500">{opt.price_per_night}</div>
            </button>
          );
        })}
      </div>
    </div>
  );
}

function TravelPlanner() {
  const { agent } = useAgent({
    agentId: "subagents",
    updates: [UseAgentUpdate.OnStateChanged],
  });

  const agentState = agent.state as TravelAgentState | undefined;

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Plan a trip",
        message: "Plan a trip to Paris for 5 days.",
      },
      {
        title: "Find flights",
        message: "Find me flights to Tokyo.",
      },
      {
        title: "Explore experiences",
        message: "What are the best experiences in Barcelona?",
      },
    ],
    available: "always",
  });

  useEffect(() => {
    if (!agentState) {
      agent.setState(INITIAL_STATE);
    }
  }, []);

  useLangGraphInterrupt({
    render: ({ event, resolve }) => (
      <InterruptHumanInTheLoop event={event} resolve={resolve} />
    ),
  });

  const activeAgent = agentState?.active_agent || "supervisor";

  return (
    <div className="flex-1 p-6 overflow-y-auto">
      {/* Itinerary Strip */}
      <div className="mb-6 p-4 bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl border border-blue-100">
        <div className="text-sm font-semibold text-gray-500 mb-2">
          Current Itinerary
        </div>
        <div className="flex flex-wrap gap-3">
          {agentState?.itinerary?.flight && (
            <div
              data-testid="selected-flight"
              className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg shadow-sm text-sm"
            >
              <span>✈</span>
              <span>
                {agentState.itinerary.flight.airline} -{" "}
                {agentState.itinerary.flight.price}
              </span>
            </div>
          )}
          {agentState?.itinerary?.hotel && (
            <div
              data-testid="selected-hotel"
              className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg shadow-sm text-sm"
            >
              <span>🏨</span>
              <span>{agentState.itinerary.hotel.name}</span>
            </div>
          )}
          {(agentState?.experiences?.length ?? 0) > 0 && (
            <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg shadow-sm text-sm">
              <span>🎯</span>
              <span>
                {agentState?.experiences?.length ?? 0} experiences planned
              </span>
            </div>
          )}
          {!agentState?.itinerary?.flight &&
            !agentState?.itinerary?.hotel &&
            (agentState?.experiences?.length ?? 0) === 0 && (
              <span className="text-sm text-gray-400">
                No items yet -- start planning!
              </span>
            )}
        </div>
      </div>

      {/* Agent Status */}
      <div className="mb-6">
        <div className="text-sm font-semibold text-gray-500 mb-2">
          Active Agent
        </div>
        <div className="flex gap-2">
          {(
            [
              {
                id: "supervisor",
                icon: "👨‍💼",
                label: "Supervisor",
              },
              { id: "flights", icon: "✈", label: "Flights" },
              { id: "hotels", icon: "🏨", label: "Hotels" },
              {
                id: "experiences",
                icon: "🎯",
                label: "Experiences",
              },
            ] as const
          ).map((a) => (
            <div
              key={a.id}
              data-testid={`${a.id}-indicator`}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm transition-all ${
                activeAgent === a.id
                  ? "bg-blue-100 text-blue-700 font-semibold border border-blue-300"
                  : "bg-gray-50 text-gray-500 border border-gray-200"
              }`}
            >
              <span>{a.icon}</span>
              <span>{a.label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Travel Details */}
      <div className="space-y-6">
        {/* Flights */}
        <div>
          <h4 className="text-md font-semibold mb-2">✈ Flight Options</h4>
          {(agentState?.flights?.length ?? 0) > 0 ? (
            <div className="space-y-2">
              {agentState!.flights.map((flight, index) => (
                <div key={index} className="p-3 bg-gray-50 rounded-lg text-sm">
                  <strong>{flight.airline}:</strong> {flight.departure} &rarr;{" "}
                  {flight.arrival} ({flight.duration}) - {flight.price}
                </div>
              ))}
              {agentState?.itinerary?.flight && (
                <div className="p-2 bg-green-50 rounded-lg text-sm text-green-700">
                  <strong>Selected:</strong>{" "}
                  {agentState.itinerary.flight.airline} -{" "}
                  {agentState.itinerary.flight.price}
                </div>
              )}
            </div>
          ) : (
            <p className="text-sm text-gray-400">No flights found yet</p>
          )}
        </div>

        {/* Hotels */}
        <div>
          <h4 className="text-md font-semibold mb-2">🏨 Hotel Options</h4>
          {(agentState?.hotels?.length ?? 0) > 0 ? (
            <div className="space-y-2">
              {agentState!.hotels.map((hotel, index) => (
                <div key={index} className="p-3 bg-gray-50 rounded-lg text-sm">
                  <strong>{hotel.name}:</strong> {hotel.location} -{" "}
                  {hotel.price_per_night} ({hotel.rating})
                </div>
              ))}
              {agentState?.itinerary?.hotel && (
                <div className="p-2 bg-green-50 rounded-lg text-sm text-green-700">
                  <strong>Selected:</strong> {agentState.itinerary.hotel.name} -{" "}
                  {agentState.itinerary.hotel.price_per_night}
                </div>
              )}
            </div>
          ) : (
            <p className="text-sm text-gray-400">No hotels found yet</p>
          )}
        </div>

        {/* Experiences */}
        <div>
          <h4 className="text-md font-semibold mb-2">🎯 Experiences</h4>
          {(agentState?.experiences?.length ?? 0) > 0 ? (
            <div className="space-y-2">
              {agentState!.experiences.map((experience, index) => (
                <div key={index} className="p-3 bg-gray-50 rounded-lg">
                  <div className="font-medium text-sm">{experience.name}</div>
                  <div className="text-xs text-gray-500 mt-1">
                    {experience.type} -- {experience.location}
                  </div>
                  <div className="text-sm text-gray-600 mt-1">
                    {experience.description}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-sm text-gray-400">No experiences planned yet</p>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import {
  useFrontendTool,
  useRenderTool,
  useConfigureSuggestions,
  CopilotChat,
} from "@copilotkit/react-core/v2";
import { CopilotKit } from "@copilotkit/react-core";
import { z } from "zod";

export default function AgenticChatDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="starterAgent">
      <Chat />
    </CopilotKit>
  );
}

function Chat() {
  const [background, setBackground] = useState<string>("#fafaf9");

  useFrontendTool({
    name: "change_background",
    description:
      "Change the background color of the chat. ONLY call this tool when the user explicitly asks to change the background. Never call it proactively or as part of another response. Can be anything that the CSS background attribute accepts. Prefer gradients.",
    parameters: z.object({
      background: z
        .string()
        .describe("The CSS background value. Prefer gradients."),
    }),
    handler: async ({ background }: { background: string }) => {
      setBackground(background);
      return {
        status: "success",
        message: `Background changed to ${background}`,
      };
    },
  });

  useRenderTool({
    name: "getWeather",
    parameters: z.object({
      location: z.string(),
    }),
    render: ({ args, result, status }: any) => {
      if (status !== "complete") {
        return (
          <div
            className="flex items-center gap-3 px-5 py-4 rounded-2xl max-w-sm"
            style={{
              background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
            }}
          >
            <div className="animate-pulse text-2xl">🌤️</div>
            <div>
              <p className="text-white font-medium text-sm">
                Checking weather...
              </p>
              <p className="text-white/60 text-xs">{args.location}</p>
            </div>
          </div>
        );
      }

      let parsed = result;
      if (typeof result === "string") {
        try {
          parsed = JSON.parse(result);
        } catch {
          parsed = {};
        }
      }

      const temp = parsed?.temperature ?? 22;
      const cond = parsed?.conditions || "Clear";
      const hum = parsed?.humidity ?? 55;
      const wind = parsed?.windSpeed ?? 12;
      const feels = parsed?.feelsLike ?? temp;

      return (
        <div
          className="rounded-2xl overflow-hidden shadow-xl my-3"
          style={{ background: getGradient(cond), width: "320px" }}
        >
          <div className="px-5 pt-4 pb-3">
            <div className="flex items-start justify-between">
              <div>
                <h3 className="text-base font-bold text-white capitalize tracking-tight">
                  {parsed?.location || args.location}
                </h3>
                <p className="text-white/50 text-[10px] font-medium uppercase tracking-wider">
                  Current Weather
                </p>
              </div>
              <span className="text-4xl leading-none">{getIcon(cond)}</span>
            </div>
            <div className="mt-3 flex items-baseline gap-1.5">
              <span className="text-4xl font-extralight text-white tracking-tighter">
                {temp}°
              </span>
              <span className="text-white/40 text-xs">
                {((temp * 9) / 5 + 32).toFixed(0)}°F
              </span>
            </div>
            <p className="text-white/70 text-xs font-medium capitalize mt-0.5">
              {cond}
            </p>
          </div>
          <div
            className="grid grid-cols-3 text-center py-2.5 px-5"
            style={{ background: "rgba(0,0,0,0.15)" }}
          >
            <div>
              <p className="text-white/40 text-[9px] font-medium uppercase tracking-wider">
                Humidity
              </p>
              <p className="text-white text-xs font-semibold mt-0.5">{hum}%</p>
            </div>
            <div className="border-x border-white/10">
              <p className="text-white/40 text-[9px] font-medium uppercase tracking-wider">
                Wind
              </p>
              <p className="text-white text-xs font-semibold mt-0.5">
                {wind} mph
              </p>
            </div>
            <div>
              <p className="text-white/40 text-[9px] font-medium uppercase tracking-wider">
                Feels Like
              </p>
              <p className="text-white text-xs font-semibold mt-0.5">
                {feels}°
              </p>
            </div>
          </div>
        </div>
      );
    },
  });

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Generate sonnet",
        message: "Write a short sonnet about AI.",
      },
      {
        title: "Weather check",
        message: "What's the weather like in Tokyo?",
      },
    ],
    available: "always",
  });

  return (
    <div
      className="flex justify-center items-center h-full w-full transition-all duration-700"
      data-testid="background-container"
      style={{ background }}
    >
      <div className="h-full w-full md:w-4/5 md:h-4/5 rounded-lg px-6">
        <CopilotChat className="h-full rounded-2xl max-w-6xl mx-auto" />
      </div>
    </div>
  );
}

function getGradient(conditions: string): string {
  const c = conditions.toLowerCase();
  if (c.includes("clear") || c.includes("sunny"))
    return "linear-gradient(135deg, #667eea 0%, #764ba2 100%)";
  if (c.includes("rain") || c.includes("storm"))
    return "linear-gradient(135deg, #4A5568 0%, #2D3748 100%)";
  if (c.includes("cloud") || c.includes("overcast"))
    return "linear-gradient(135deg, #718096 0%, #4A5568 100%)";
  if (c.includes("snow"))
    return "linear-gradient(135deg, #63B3ED 0%, #4299E1 100%)";
  return "linear-gradient(135deg, #667eea 0%, #764ba2 100%)";
}

function getIcon(conditions: string): string {
  const c = conditions.toLowerCase();
  if (c.includes("clear") || c.includes("sunny")) return "☀️";
  if (c.includes("rain") || c.includes("drizzle")) return "🌧️";
  if (c.includes("snow")) return "❄️";
  if (c.includes("thunderstorm")) return "⛈️";
  if (c.includes("cloud") || c.includes("overcast")) return "☁️";
  if (c.includes("fog")) return "🌫️";
  return "🌤️";
}

